function getChainKey(chainId: unknown) {
  return String(chainId || "").trim();
}

function getExplorerTxBaseUrl(blockExplorerUrl: string) {
  return `${blockExplorerUrl.replace(/\/+$/, "")}/tx/`;
}

export function getChainName(chainId: unknown) {
  const chain = getChainKey(chainId);
  if (!chain) return "-";
  return CHAIN_EXPLORER_INFO[chain]?.name || `Chain ${chain}`;
}

export function getExplorerTxUrl(chainId: unknown, txId: unknown) {
  const tx = String(txId || "").trim();
  if (!tx) return "";
  const chain = getChainKey(chainId);
  const explorer = CHAIN_EXPLORER_INFO[chain]?.blockExplorerUrl;
  return explorer ? `${getExplorerTxBaseUrl(explorer)}${tx}` : "";
}

export function formatAddress(address: string) {
  return address.length > 10
    ? `${address.slice(0, 6)}...${address.slice(-4)}`
    : address;
}

export function formatTokenAmount(value: unknown) {
  const numeric = Number(value ?? 0);
  if (!Number.isFinite(numeric)) return "0";
  return numeric.toLocaleString(undefined, { maximumFractionDigits: 8 });
}
